/**
 * NotFoundPage Component
 *
 * 404エラーページ。
 * 存在しないルートにアクセスした際に表示されます。
 *
 * ルート: * (すべての未定義ルート)
 */

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Button } from '../components';

/**
 * NotFoundPageコンポーネント
 * 404エラーページを提供します
 */
const NotFoundPage: React.FC = () => {
  const navigate = useNavigate();

  const handleGoHome = () => {
    navigate('/', { replace: true });
  };

  const handleGoBack = () => {
    navigate(-1);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center px-4 sm:px-6 lg:px-8">
      <div className="max-w-md w-full text-center">
        {/* 404 Icon */}
        <div className="mb-8">
          <svg
            className="mx-auto h-32 w-32 text-primary-600"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={1.5}
              d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
            />
          </svg>
        </div>

        {/* Error Message */}
        <h1 className="text-6xl font-bold text-gray-900 mb-4">404</h1>
        <h2 className="text-3xl font-semibold text-gray-700 mb-4">Page Not Found</h2>
        <p className="text-gray-600 mb-8">
          Sorry, we couldn&apos;t find the page you&apos;re looking for. The page might have been
          moved, deleted, or never existed.
        </p>

        {/* Action Buttons */}
        <div className="space-y-3">
          <Button variant="primary" fullWidth onClick={handleGoHome}>
            Go to Home
          </Button>
          <Button variant="ghost" fullWidth onClick={handleGoBack}>
            Go Back
          </Button>
        </div>

        {/* Help Links */}
        <div className="mt-8 pt-8 border-t border-gray-200">
          <p className="text-sm text-gray-600 mb-4">Need help? Try these links:</p>
          <div className="flex justify-center space-x-4 text-sm">
            <a href="/login" className="text-primary-600 hover:text-primary-700 underline">
              Login
            </a>
            <span className="text-gray-400">|</span>
            <a href="/register" className="text-primary-600 hover:text-primary-700 underline">
              Register
            </a>
          </div>
        </div>
      </div>
    </div>
  );
};

export default NotFoundPage;
